lessons.solution:
class StackNavigator:
    def __init__(self, initial_route):
        self.stack = [initial_route]

    def push(self, screen):
        self.stack.append(screen)
        print(f"Navigated to {screen}")

    def pop(self):
        if len(self.stack) > 1:
            removed = self.stack.pop()
            print(f"Went back from {removed}")
        else:
            print("Cannot go back, at root screen!")

    def current(self):
        return self.stack[-1]

nav = StackNavigator('Home')
nav.push('Profile')
nav.push('Settings')
print("Current screen:", nav.current())
nav.pop()
print("Current screen:", nav.current())

